  currentPage?: "dashboard" | "about" | "chat" | "storage" | "login" | "signup";
  activeTab?: "energy-dashboard" | "energy-trading" | "simulation";
  onTabChange?: (
    tab: "energy-dashboard" | "energy-trading" | "simulation"
  ) => void;
}

export default function Navbar({
  currentPage,
  activeTab,
  onTabChange,
