                <Link href="/?tab=energy-dashboard">
                  <button className="text-secondary-custom hover:text-primary transition-all duration-300 ease-in-out transform hover:scale-105">
                    Energy Dashboard
                  </button>
                </Link>
                <Link href="/?tab=energy-trading">
                  <button className="text-secondary-custom hover:text-primary transition-all duration-300 ease-in-out transform hover:scale-105">
                    Energy Trading
                  </button>
                </Link>
              </>
