            <Link href="/about">
              <button
                className={`transition-all duration-300 ease-in-out transform hover:scale-105 ${
                  currentPage === "about"
                    ? "text-primary font-medium"
                    : "text-secondary-custom hover:text-primary"
                }`}>
                About
