                          </div>
                          <div className="text-sm md:text-base leading-relaxed prose prose-sm md:prose-base max-w-none dark:prose-invert">
                            {msg.sender === "ai" ? (
                              <ReactMarkdown
                                remarkPlugins={[remarkGfm]}
                                components={{
                                  p: ({ children }) => (
