                                  em: ({ children }) => (
                                    <em className="italic text-gray-800 dark:text-gray-200">
                                      {children}
                                    </em>
                                  ),
                                  h1: ({ children }) => (
                                    <h1 className="text-lg sm:text-xl font-bold mb-3 mt-3 text-gray-900 dark:text-gray-100">
                                      {children}
                                    </h1>
                                  ),
