                              SolarSense AI
                            </span>
                            <span className="text-xs text-muted-foreground">
                              Analyzing...
                            </span>
                          </div>
                          <div className="flex items-center gap-2">
                            <div className="animate-bounce w-1.5 h-1.5 sm:w-2 sm:h-2 bg-purple-500 rounded-full"></div>
