    const updateData = {
      ...data,
      pricePerKwh: data.pricePerKwh, // Backend will convert to cents
      sellerHouseholdId: data.tradeType === 'sell' ? userHouseholdId : undefined,
      buyerHouseholdId: data.tradeType === 'buy' ? userHouseholdId : undefined,
