  return (
    <ToastPrimitives.Root
      ref={ref}
      className={cn(toastVariants({ variant }), className)}
      {...props}
    >
      <div className="flex items-center space-x-3">
        {getIcon()}
        <div className="flex-1 min-w-0">
          {props.children}
        </div>
      </div>
